// Date math: yesterday (GSC has 1-2 day lag, so target day-2)
const now = new Date();
const targetDate = new Date(now.getTime() - 2 * 24 * 60 * 60 * 1000);
const windowStart = new Date(now.getTime() - 9 * 24 * 60 * 60 * 1000);
const fmt = (d) => d.toISOString().split('T')[0];
return [{ json: { targetDate: fmt(targetDate), windowStart: fmt(windowStart), windowEnd: fmt(targetDate) } }];

// Refresh GSC OAuth access token
const res = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: new URLSearchParams({
    client_id: $env.GSC_CLIENT_ID,
    client_secret: $env.GSC_CLIENT_SECRET,
    refresh_token: $env.GSC_REFRESH_TOKEN,
    grant_type: 'refresh_token'
  }).toString()
});
const data = typeof res === 'string' ? JSON.parse(res) : res;
return [{ json: { ...$json, accessToken: data.access_token } }];

// Pre-build the GSC API payload (per feedback_n8n_json_golden_rule)
const body = {
  startDate: $json.windowStart,
  endDate: $json.windowEnd,
  dimensions: ['date'],
  rowLimit: 30
};
return [{ json: { ...$json, gscBody: body } }];

// Compute deltas + 7-day avg for the target date row
const rows = $json.rows || [];
if (rows.length === 0) {
  throw new Error('No GSC data returned for window');
}

// Find the target date in the returned rows
const targetDate = $('Calc Dates').first().json.targetDate;
const targetIdx = rows.findIndex(r => r.keys[0] === targetDate);
if (targetIdx === -1) {
  throw new Error(`Target date ${targetDate} not in GSC response`);
}
const target = rows[targetIdx];
const prev = targetIdx > 0 ? rows[targetIdx - 1] : null;

// 7-day rolling avg ending on target
const window = rows.slice(Math.max(0, targetIdx - 6), targetIdx + 1);
const avg7Clicks = Math.round(window.reduce((s, r) => s + r.clicks, 0) / window.length);
const avg7Imp = Math.round(window.reduce((s, r) => s + r.impressions, 0) / window.length);

// Status auto-flagging
let status = 'stable';
const dC = prev ? target.clicks - prev.clicks : 0;
const dP = prev ? +(target.position - prev.position).toFixed(2) : 0;
if (dC <= -25 && Math.abs(dC / Math.max(prev?.clicks || 1, 1)) > 0.5) status = 'click-collapse';
else if (dP >= 1.0) status = 'position-drop';
else if (dC > 10 && dP < 0) status = 'growth';

// Build Notion properties payload
const notionProps = {
  Name: { title: [{ text: { content: targetDate } }] },
  Date: { date: { start: targetDate } },
  Clicks: { number: target.clicks },
  Impressions: { number: target.impressions },
  CTR: { number: +target.ctr.toFixed(4) },
  'Avg Position': { number: +target.position.toFixed(2) },
  'Δ Clicks': prev ? { number: dC } : { number: null },
  'Δ Impressions': prev ? { number: target.impressions - prev.impressions } : { number: null },
  'Δ Position': prev ? { number: dP } : { number: null },
  '7-day Avg Clicks': { number: avg7Clicks },
  '7-day Avg Impressions': { number: avg7Imp },
  Period: { select: { name: 'daily' } },
  Status: { select: { name: status } },
  Notes: { rich_text: [] }
};

return [{ json: { targetDate, notionProps } }];

// Query Notion DB to check if target date row already exists
const dsId = '3543d42c-4a9c-8083-b92a-000bad01dce2';
const res = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.notion.com/v1/data_sources/${dsId}/query`,
  headers: {
    'Authorization': `Bearer ${$env.NOTION_TOKEN}`,
    'Notion-Version': '2026-03-11',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    filter: {
      property: 'Date',
      date: { equals: $json.targetDate }
    }
  }),
  json: false
});
const data = typeof res === 'string' ? JSON.parse(res) : res;
const existingId = data.results?.[0]?.id || null;
return [{ json: { ...$json, existingId } }];

// Upsert: PATCH if existing, POST if new
const props = $json.notionProps;
const existingId = $json.existingId;
const dsId = '3543d42c-4a9c-8083-b92a-000bad01dce2';

if (existingId) {
  const res = await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://api.notion.com/v1/pages/${existingId}`,
    headers: {
      'Authorization': `Bearer ${$env.NOTION_TOKEN}`,
      'Notion-Version': '2026-03-11',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ properties: props }),
    json: false
  });
  return [{ json: { action: 'updated', date: $json.targetDate, response: typeof res === 'string' ? JSON.parse(res) : res } }];
} else {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/pages',
    headers: {
      'Authorization': `Bearer ${$env.NOTION_TOKEN}`,
      'Notion-Version': '2026-03-11',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      parent: { type: 'data_source_id', data_source_id: dsId },
      properties: props
    }),
    json: false
  });
  return [{ json: { action: 'created', date: $json.targetDate, response: typeof res === 'string' ? JSON.parse(res) : res } }];
}
